INSERT INTO `quizzes` (`id`, `question`, `option_a`, `option_b`, `option_c`, `option_d`, `correct_option`, `created_at`, `updated_at`) VALUES (1, 'Adi Parwa Menceritakan Tentang Kisah Siapa?', 'Kisah perang besar Bharatayuddha', 'Kisah perjalanan Pandawa setelah perang', 'Kisah asal-usul keturunan Raja Yayati hingga lahirnya Pandawa dan Korawa', 'Kisah kepemimpinan Yudhisthira sebagai raja Hastinapura', 'C', '2026-01-25 00:46:03', '2026-01-25 00:46:03');
INSERT INTO `quizzes` (`id`, `question`, `option_a`, `option_b`, `option_c`, `option_d`, `correct_option`, `created_at`, `updated_at`) VALUES (2, 'Dalam Adi Parwa, terdapat kisah "Pemutaran Mandara Giri" (Amerta Manthana). Siapakah tokoh yang berhasil mendapatkan Tirta Amerta dengan menyamar sebagai wanita cantik bernama Mohini?', 'Dewa Indra', 'Dewa Wisnu', 'Dewa Siwa', 'Dewa Brahma', 'B', '2026-01-25 05:44:16', '2026-01-25 05:44:16');
INSERT INTO `quizzes` (`id`, `question`, `option_a`, `option_b`, `option_c`, `option_d`, `correct_option`, `created_at`, `updated_at`) VALUES (3, 'Pada Sabha Parwa, alasan teknis mengapa Yudistira tidak bisa menolak undangan permainan dadu dari Sakuni meskipun ia tahu itu berisiko adalah...', 'Ancaman perang dari Duryodana', 'Perintah langsung dari Dretarastra', 'Sumpah kasta Ksatriya untuk tidak menolak tantangan judi atau perang', 'Jebakan mantra sihir dari Sakuni', 'C', '2026-01-25 05:45:11', '2026-01-25 05:45:11');
INSERT INTO `quizzes` (`id`, `question`, `option_a`, `option_b`, `option_c`, `option_d`, `correct_option`, `created_at`, `updated_at`) VALUES (4, 'Kitab Udyoga Parwa dianggap sebagai salah satu bagian paling krusial karena berisi tentang...', 'Strategi formasi perang (Wyuha)', 'Usaha diplomasi terakhir dan persiapan menuju perang Baratayuda', 'Perjanjian pembagian kerajaan secara adil', 'Pengangkatan Bhisma sebagai Panglima Tertinggi', 'B', '2026-01-25 05:46:09', '2026-01-25 05:46:09');
INSERT INTO `quizzes` (`id`, `question`, `option_a`, `option_b`, `option_c`, `option_d`, `correct_option`, `created_at`, `updated_at`) VALUES (5, 'Dalam Bhisma Parwa, Krishna melanggar sumpahnya sendiri untuk tidak memegang senjata selama perang karena melihat Arjuna ragu melawan Bhisma. Senjata apa yang diambil Krishna saat itu?', 'Busur Gandiwa', 'Gada Kaumodaki', 'Roda kereta (Cakra)', 'Pedang Nandaka', 'C', '2026-01-25 05:46:52', '2026-01-25 05:46:52');
INSERT INTO `quizzes` (`id`, `question`, `option_a`, `option_b`, `option_c`, `option_d`, `correct_option`, `created_at`, `updated_at`) VALUES (6, 'Karna Parwa menceritakan gugurnya Karna di tangan Arjuna. Siapakah yang menjadi kusir kereta Karna yang terus-menerus menjatuhkan mental Karna dengan kata-katanya?', 'Sangkuni', 'Raja Salya', 'Kripacharya', 'Duryodana', 'B', '2026-01-25 05:47:33', '2026-01-25 05:47:33');
INSERT INTO `quizzes` (`id`, `question`, `option_a`, `option_b`, `option_c`, `option_d`, `correct_option`, `created_at`, `updated_at`) VALUES (7, 'Stri Parwa merupakan kitab yang sangat emosional karena berisi ratapan para wanita. Siapakah yang memberikan kutukan kepada Krishna bahwa bangsa Yadawa akan hancur dengan cara yang sama seperti Korawa?', 'Kunti', 'Drupadi', 'Gandari', 'Satyawati', 'C', '2026-01-25 05:48:20', '2026-01-25 05:48:20');
INSERT INTO `quizzes` (`id`, `question`, `option_a`, `option_b`, `option_c`, `option_d`, `correct_option`, `created_at`, `updated_at`) VALUES (8, 'Dalam Aswamedhika Parwa, Yudistira melaksanakan upacara korban kuda untuk menyucikan diri. Siapakah ksatria yang ditugaskan mengawal kuda tersebut berkeliling dunia?', 'Bima', 'Arjuna', 'Nakula', 'Sadewa', 'B', '2026-01-25 05:48:53', '2026-01-25 05:48:53');
INSERT INTO `quizzes` (`id`, `question`, `option_a`, `option_b`, `option_c`, `option_d`, `correct_option`, `created_at`, `updated_at`) VALUES (9, 'Kitab Anusasana Parwa berisi wejangan terakhir Bhisma sebelum wafat. Bhisma menunggu waktu yang tepat untuk meninggal sampai matahari berada di lintasan utara yang disebut...', 'Dakshinayana', 'Uttarayana', 'Madhyayana', 'Suryayana', 'B', '2026-01-25 05:49:31', '2026-01-25 05:49:31');
INSERT INTO `quizzes` (`id`, `question`, `option_a`, `option_b`, `option_c`, `option_d`, `correct_option`, `created_at`, `updated_at`) VALUES (10, 'Pada Mausala Parwa, kehancuran bangsa Yadawa bermula dari kutukan para Rsi karena lelucon yang dibuat oleh putra Krishna yang menyamar sebagai wanita hamil. Siapakah putra yang dimaksud?', 'Pradyumna', 'Aniruddha', 'Samba', 'Gada', 'C', '2026-01-25 05:50:11', '2026-01-25 05:50:11');
INSERT INTO `quizzes` (`id`, `question`, `option_a`, `option_b`, `option_c`, `option_d`, `correct_option`, `created_at`, `updated_at`) VALUES (12, 'Kitab terakhir dari Asta Dasa Parwa yang menceritakan Yudistira mencapai surga dan bertemu saudara-saudaranya adalah...', 'Shanti Parwa', 'Anusasana Parwa', 'Swargarohana Parwa', 'Adi Parwa', 'C', '2026-01-25 05:51:47', '2026-01-25 05:51:47');
